import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, EventEmitter, Input, Output, ViewEncapsulation, } from '@angular/core';
import { LucideAngularModule, ChevronRight } from 'lucide-angular';
/**
 * Fil d'Ariane sémantique : `<nav aria-label>` + `<ol>` ordonné +
 * `aria-current="page"` sur le dernier item.
 */
let OriBreadcrumbComponent = class OriBreadcrumbComponent {
    constructor() {
        this.items = [];
        this.separator = '';
        this.ariaLabel = "Fil d'Ariane";
        this.itemClick = new EventEmitter();
        this.ChevronIcon = ChevronRight;
    }
    onClick(event, index, item) {
        this.itemClick.emit({ index, item, event });
    }
    static { this.propDecorators = {
        items: [{ type: Input }],
        separator: [{ type: Input }],
        ariaLabel: [{ type: Input }],
        itemClick: [{ type: Output }]
    }; }
};
